const concept = $.input.videoConcept;
const platforms = $.input.targetPlatforms || 'TikTok, YouTube Shorts, Instagram Reels';
const count = parseInt($.input.videoCount || '3', 10);
const date = new Date().toISOString().split('T')[0];

let prompt = 'You are a viral short-form video strategist and scriptwriter with expertise in TikTok, YouTube Shorts, and Instagram Reels. You understand hooks, retention patterns, trending formats, and what makes content go viral.\n\n';
prompt += 'VIDEO CONCEPT: ' + concept + '\n';
prompt += 'TARGET PLATFORMS: ' + platforms + '\n';
prompt += 'NUMBER OF VARIATIONS: ' + count + '\n\n';
prompt += 'For each video variation, create a complete production plan. Return ONLY valid JSON, no markdown or code fences.\n\n';
prompt += 'Return a JSON object with this exact structure:\n';
prompt += '{\n';
prompt += '  "concept": "the refined concept",\n';
prompt += '  "targetAudience": "who this content is for",\n';
prompt += '  "viralPotentialScore": 1-10,\n';
prompt += '  "videos": [\n';
prompt += '    {\n';
prompt += '      "title": "catchy video title",\n';
prompt += '      "hook": "first 3 seconds hook text",\n';
prompt += '      "duration": "recommended duration in seconds",\n';
prompt += '      "format": "trend format name (e.g. POV, Get Ready With Me, Day in Life)",\n';
prompt += '      "script": "full script with timing cues",\n';
prompt += '      "scenes": [\n';
prompt += '        { "timestamp": "0:00-0:03", "visual": "what the viewer sees", "audio": "voiceover or sound", "text_overlay": "on-screen text" }\n';
prompt += '      ],\n';
prompt += '      "music": "recommended music/sound style",\n';
prompt += '      "hashtags": ["relevant", "hashtags"],\n';
prompt += '      "caption": "post caption",\n';
prompt += '      "platformNotes": { "tiktok": "platform-specific tips", "youtube": "tips", "instagram": "tips" },\n';
prompt += '      "cta": "call to action"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "productionTips": ["tip1", "tip2"],\n';
prompt += '  "trendingElements": ["trending sounds or formats to leverage"],\n';
prompt += '  "postingStrategy": { "bestTimes": "recommended posting times", "frequency": "posting cadence", "crossPostOrder": "which platform first" }\n';
prompt += '}\n';

return { prompt, date, concept };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { concept: $.input.videoConcept, videos: [], text: raw }; }

const ai = $.steps.parseAI.output;
const date = $.steps.buildPrompt.output.date;
const videos = ai.videos || [];

const sheetData = videos.map((v, i) => ({
  '#': i + 1,
  'Title': v.title || '',
  'Hook': v.hook || '',
  'Format': v.format || '',
  'Duration': v.duration || '',
  'Music/Sound': v.music || '',
  'Hashtags': (v.hashtags || []).join(', '),
  'Caption': v.caption || '',
  'CTA': v.cta || '',
  'Scene Count': (v.scenes || []).length,
  'Script Preview': (v.script || '').slice(0, 300),
  'Status': 'Draft',
  'Date Generated': date
}));

return { sheetData, videoCount: videos.length, concept: ai.concept || $.input.videoConcept };

const ai = $.steps.parseAI.output;
const videos = ai.videos || [];
const concept = ai.concept || $.input.videoConcept;
const score = ai.viralPotentialScore || 'N/A';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Viral Video Scripts Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Concept:* ' + concept + '\n*Viral Potential:* ' + score + '/10\n*Videos Generated:* ' + videos.length } });
blocks.push({ type: 'divider' });

videos.forEach((v, i) => {
  let text = '*' + (i + 1) + '. ' + (v.title || 'Untitled') + '*\n';
  text += ':hook: *Hook:* ' + (v.hook || '') + '\n';
  text += ':movie_camera: *Format:* ' + (v.format || '') + ' | *Duration:* ' + (v.duration || '') + '\n';
  text += ':musical_note: *Music:* ' + (v.music || '') + '\n';
  if (v.hashtags && v.hashtags.length) text += ':hash: ' + v.hashtags.slice(0, 5).join(' ') + '\n';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
  if (i < videos.length - 1) blocks.push({ type: 'divider' });
});

if (ai.postingStrategy) {
  blocks.push({ type: 'divider' });
  let stratText = '*Posting Strategy*\n';
  if (ai.postingStrategy.bestTimes) stratText += ':clock3: ' + ai.postingStrategy.bestTimes + '\n';
  if (ai.postingStrategy.frequency) stratText += ':calendar: ' + ai.postingStrategy.frequency + '\n';
  if (ai.postingStrategy.crossPostOrder) stratText += ':arrows_counterclockwise: ' + ai.postingStrategy.crossPostOrder;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: stratText } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Production plan saved to Google Sheets | Generated by Claude AI' }] });

const fallback = 'Viral Video Scripts: ' + videos.length + ' variations for "' + concept + '" — viral score ' + score + '/10';

return { blocks, fallback };
